 actions.', 'agentic_ai', '{\"principle\": \"tool_first\", \"kiss\": true}'),\n('OpenAI Agents Handoffs', 'Seamless transfer of control and context between specialized agents via handoffs.', 'agentic_ai', '{\"framework\": \"OpenAI Agents SDK\", \"feature\": \"handoffs\"}'),\n('Google ADK Modular Hierarchies', 'Composable hierarchies of specialized agents for scalable applications.', 'agentic_ai', '{\"framework\": \"Google ADK\", \"multi_agent\": true}'),\n('Microsoft AutoGen Collaboration', 'Framework enabling autonomous or human-collaborative multi-agent applications.', 'agentic_ai', '{\"framework\": \"AutoGen\", \"collaboration\": \"human_ai\"}'),\n('Prompt Canvas Guide', 'Structured: user persona, task/intent, CoT optimization, emotion prompting.', 'prompt_engineering', '{\"framework\": \"Prompt Canvas\", \"lit_review\": true}'),\n('D4RT 4D Perception', 'Transforms video into real-time 4D perception, replacing complex pipelines.', 'reasoning', '{\"vision\": \"4D\", \"source\": \"Binary Verse AI 2026\"}'),\n('Claude Constitutional AI', 'Public constitutional principles enforcing safe and aligned AI behavior.', 'agentic_ai', '{\"anthropic\": \"Claude\", \"alignment\": \"constitution\"}');\n